% ============================================================
% POLICY RULES (executable Prolog sketches)
% ============================================================

% Research misconduct definition
is_research_misconduct(Act) :-
    member(Act, [fabrication, falsification, plagiarism]).
not_research_misconduct(honest_error).
not_research_misconduct(difference_of_opinion).

% Inquiry committee minimum size
inquiry_minimum_size(3).
investigation_minimum_size(5).

% Extension authority differs by stage
extension_authority(inquiry, research_integrity_officer).
extension_authority(investigation, provost).
% NOTE: RIO cannot grant investigation extensions. Provost cannot grant inquiry extensions.

% Conflict of interest check
has_conflict(Person, Other) :-
    conflict_of_interest(Person, Other, coauthorship, PubDate),
    conflict_window_active(Person, Other, PubDate, WindowEnd).

% Grant status inheritance
subgrant_inherits_status(SubID, Status) :-
    subgrant(SubID, ParentID, _),
    grant_status(ParentID, Status, _).

% Equipment disposition on grant termination
equipment_reverts_to_department(EquipID) :-
    equipment_grant(EquipID, GrantID),
    grant_status(GrantID, terminated, _).

