% FSRB decision types
fsrb_may(uphold).
fsrb_may(modify).
fsrb_may(overturn).
fsrb_decision_final(yes).

% Post-overturn obligations
% If FSRB overturns: notify agency within 10 business days, expunge within 5 business days
% If FSRB upholds/modifies: sanctions take effect immediately unless FSRB specifies otherwise
